// Parse streaming response from Ollama
const rawData = $input.first().json.data;

// Split by newline and parse each chunk
const chunks = rawData.split('\n')
  .filter(line => line.trim() !== '')
  .map(line => {
    try { return JSON.parse(line); } 
    catch(e) { return null; }
  })
  .filter(chunk => chunk !== null);

// Join all response chunks into one full text
const ollamaResponse = chunks
  .map(chunk => chunk.response || '')
  .join('');

// Get test data from Code Node 1 - replace 'Code' with your exact node name
let rawTestData = $('Code in JavaScript').first().json;
if (rawTestData.data) rawTestData = rawTestData.data;

// Filter out __EMPTY
const devices = Object.entries(rawTestData)
  .filter(([key]) => !key.includes('__EMPTY') && !key.includes('prompt'));

const deviceStats = devices.map(([device, counts]) => {
  const total = (counts.Pass || 0) + (counts.Fail || 0) + (counts.NotRun || 0);
  const passRate = total > 0 ? ((counts.Pass / total) * 100).toFixed(1) : 0;
  const failRate = total > 0 ? ((counts.Fail / total) * 100).toFixed(1) : 0;
  return { device, counts, total, passRate, failRate };
});

const html = `
