const base64Html = Buffer.from(html, 'utf8').toString('base64');
return [{ json: { html_report: base64Html } }];

const data = $input.all();
let result = {};

// Columns to always ignore - add any non-device columns here
const ignoreColumns = [
  "SL No",
  "Module",
  "Sub Module",
  "Test Case ID",
  "Test Case Description",
  "Priority",
  "Pre Condition",
  "Test Steps",
  "Expected Result",
  "Test Case Type",
  "P/N",
  "Issues ID",
  "__EMPTY"
];

// All possible variations of Pass/Fail/NotRun values
const passValues   = ["pass", "passed", "p", "yes", "ok", "true"];
const failValues   = ["fail", "failed", "f", "no", "false", "error"];
const notRunValues = ["not run", "notrun", "nr", "n/a", "na", "skip", "skipped", "blocked", ""];

data.forEach(item => {
  const row = item.json;
  Object.keys(row).forEach(column => {

    // Skip ignored columns and any __EMPTY variants
    if (ignoreColumns.includes(column)) return;
    if (column.includes('__EMPTY')) return;
    if (column.trim() === '') return;

    const status = String(row[column] || '').trim().toLowerCase();

    if (!result[column]) {
      result[column] = { Pass: 0, Fail: 0, NotRun: 0 };
    }

    if (passValues.includes(status)) {
      result[column].Pass++;
    } else if (failValues.includes(status)) {
      result[column].Fail++;
    } else {
      // Anything unrecognised goes to NotRun
      result[column].NotRun++;
    }
  });
});

return [{ json: result }];

const data = $input.first().json;

// Filter out __EMPTY
const devices = Object.entries(data)
  .filter(([key]) => !key.includes('__EMPTY'));

// Pre-calculate everything before sending to Ollama
const deviceSummary = devices.map(([device, counts]) => {
  const total = (counts.Pass || 0) + (counts.Fail || 0) + (counts.NotRun || 0);
  const passRate = total > 0 ? ((counts.Pass / total) * 100).toFixed(1) : 0;
  const failRate = total > 0 ? ((counts.Fail / total) * 100).toFixed(1) : 0;
  return `${device}: Pass=${counts.Pass}, Fail=${counts.Fail}, NotRun=${counts.NotRun}, Total=${total}, PassRate=${passRate}%, FailRate=${failRate}%`;
}).join('\n');

return [{
  json: {
    prompt: `You are a QA analyst. Here is the pre-calculated test execution data:\n${deviceSummary}\n\nUsing ONLY the numbers above, provide:\n1) Overall quality status Good or Average or Poor based on average pass rate\n2) Best device name with its exact pass rate from above\n3) Worst device name with its exact pass rate from above\n4) One short recommendation\nPlain text only, max 5 lines, no bullet symbols, use exact numbers from the data above.`
  }
}];
